import React, { useEffect, useState } from 'react';
import FormControl from '@material-ui/core/FormControl';
import InputLabel from '@material-ui/core/InputLabel';
import Select from '@material-ui/core/Select';
import MenuItem from '@material-ui/core/MenuItem';

function CategorySelect({
  selectedCategory,
  showExistingCategories,
  handleSelectChange,
  menuData,
  handleSubCategoryChange,
  existingCategories,
}) {
  const [selectedSubCategories, setSelectedSubCategories] = useState([]);

  useEffect(() => {
    if (showExistingCategories && existingCategories.length > 0) {
      const existingMainCategory = existingCategories[0].main;
      handleSelectChange({ target: { value: existingMainCategory } });

      const existingSubCategories = existingCategories.reduce(
        (acc, category) => acc.concat(category.sub),
        []
      );
      setSelectedSubCategories(existingSubCategories);
    }
  }, [showExistingCategories, existingCategories, handleSelectChange]);

  return (
    <div>
      <FormControl variant="outlined">
        <InputLabel id="category">Category</InputLabel>
        <Select
          labelId="category"
          id="category"
          value={selectedCategory}
          onChange={handleSelectChange}
          label="Category"
        >
          {menuData.categories.map((category, index) => (
            <MenuItem key={index} value={category.main}>
              {category.main}
            </MenuItem>
          ))}
        </Select>
      </FormControl>
      {selectedCategory && (
        <FormControl variant="outlined">
          <InputLabel id="subCategory">Sub Category</InputLabel>
          <Select
            labelId="subCategory"
            id="subCategory"
            multiple
            value={selectedSubCategories}
            onChange={handleSubCategoryChange}
            label="Sub Category"
          >
            {menuData.subCategories[selectedCategory]?.map(
              (subCategory, index) => (
                <MenuItem key={index} value={subCategory}>
                  {subCategory}
                </MenuItem>
              )
            )}
          </Select>
        </FormControl>
      )}
    </div>
  );
}

export default CategorySelect;
